package problems;

public class bestTimeToBuyAndSell {

    public static void main(String[] args) {
        int[] prices = {17, 1, 5, 3, 6, 4};
        System.out.println("Maximum profits are " + maxProfit(prices));
    }

    /**
     * One-pass algorithm to find maximum profit.
     * Track minimum price seen so far and calculate profit at each step.
     * 
     * Time: O(n), Space: O(1)
     * 
     * Algorithm:
     * - Keep track of minimum price encountered
     * - At each price, calculate potential profit if selling today
     * - Update maximum profit if current profit is higher
     */
    public static int maxProfit(int[] prices) {
        int min = prices[0];
        int profit = 0;

        for (int i = 0; i < prices.length; i++) {
            // Update minimum price if we found a lower one
            if (prices[i] < min) {
                min = prices[i];
            }
            // Calculate profit if we sell at current price
            profit = Math.max(profit, prices[i] - min);
        }

        return profit;
    }
}

// Example 1:
// Input: prices = [17,1,5,3,6,4]
// Output: 5
// Explanation: Buy on day 2 (price = 1) and sell on day 5 (price = 6)
// Profit = 6 - 1 = 5

// Example 2:
// Input: prices = [17,6,4,3,1]
// Output: 0
// Explanation: No transactions done, max profit = 0
